effect.shader:
void main() {

    vec2 st = acScreenNorm;
    vec2 fragSize = vec2(1.)/getTexSize(inputImg.size) * radius;
    vec4 w  = texture2DCv(inputImg.texture, vec2(acScreenNorm.x - fragSize.x, acScreenNorm.y) );
    vec4 e  = texture2DCv(inputImg.texture, vec2(acScreenNorm.x + fragSize.x, acScreenNorm.y) );
    vec4 n  = texture2DCv(inputImg.texture, vec2(acScreenNorm.x, acScreenNorm.y + fragSize.y) );
    vec4 s  = texture2DCv(inputImg.texture, vec2(acScreenNorm.x, acScreenNorm.y - fragSize.y) );
    vec4 texColor = texture2DCv(inputImg.texture, acScreenNorm);

    float centerWeight = 1. + strength*4.;
    float sideWeight = -strength;

    gl_FragColor = n*sideWeight + s*sideWeight + e*sideWeight + w*sideWeight + texColor*centerWeight;

}
